INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 1, 19200017, 115711, "フードコートで提供予定だったプリンが\n担当者が目を離した隙にすべて消失…", 10, 920, 11, 0, 0.5, 0);
