INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 1, 19420019, 113211, "はーっはっはっは！\nこうして水の上をたゆたっていると\nあの冒険を思い出すな！", 6, 942, 11, 0, 1, 0);
